 5→//! GetCoronets command - List Coronets for a Heat
 6→//!
 7→//! Queries a Gallops JSON file and outputs coronets (pace identities) for a specified heat,
 8→//! with optional filtering for remaining or rough paces only.
 9→
10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
12→use std::path::PathBuf;
13→
14→/// Arguments for jjx_get_coronets command
15→#[derive(clap::Args, Debug)]
16→pub struct jjrgc_GetCoronetsArgs {
17→    /// Path to the Gallops JSON file
18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
19→    pub file: PathBuf,
20→
21→    /// Target Heat identity (Firemark)
22→    pub firemark: String,
23→
24→    /// Exclude complete and abandoned paces
25→    #[arg(long)]
26→    pub remaining: bool,
27→
28→    /// Include only rough paces
29→    #[arg(long)]
30→    pub rough: bool,
31→}
32→
33→/// Run the get_coronets command - output coronets one per line
34→pub fn jjrgc_run_get_coronets(args: jjrgc_GetCoronetsArgs) -> i32 {
35→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
36→        Ok(fm) => fm,
37→        Err(e) => {
38→            eprintln!("jjx_get_coronets: error: {}", e);
39→            return 1;
40→        }
41→    };
42→
43→    let gallops = match Gallops::jjrg_load(&args.file) {
44→        Ok(g) => g,
45→        Err(e) => {
46→            eprintln!("jjx_get_coronets: error: {}", e);
47→            return 1;
48→        }
49→    };
50→
51→    let heat_key = firemark.jjrf_display();
52→    let heat = match gallops.heats.get(&heat_key) {
53→        Some(h) => h,
54→        None => {
55→            eprintln!("jjx_get_coronets: error: Heat '{}' not found", heat_key);
56→            return 1;
57→        }
58→    };
59→
60→    for coronet_key in &heat.order {
61→        if let Some(pace) = heat.paces.get(coronet_key) {
62→            if let Some(tack) = pace.tacks.first() {
63→                // Apply --remaining filter: skip complete/abandoned
64→                if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
65→                    continue;
66→                }
67→                // Apply --rough filter: only include rough
68→                if args.rough && tack.state != PaceState::Rough {
69→                    continue;
70→                }
71→                println!("{}", coronet_key);
72→            }
73→        }
74→    }
75→
76→    0
77→}
