/// Capture for handlers returning (i32, String) — buf-based output.
///
/// Still redirects stdout via pipe to catch any residual println! from
/// helper functions not yet migrated (e.g. jjrpd_print_file_bitmap).
/// Combines pipe-captured stdout with the returned buf string.
fn jjrm_capture_buf<F: FnOnce() -> (i32, String)>(f: F) -> Result<CallToolResult, McpError> {
    use std::io::{Read, Write};
    use std::os::unix::io::FromRawFd;

    unsafe {
        let mut fds = [0i32; 2];
        if libc::pipe(fds.as_mut_ptr()) != 0 {
            return Err(McpError::internal_error("pipe creation failed", None));
        }
        let (read_fd, write_fd) = (fds[0], fds[1]);

        let saved = libc::dup(libc::STDOUT_FILENO);
        if saved < 0 {
            libc::close(read_fd);
            libc::close(write_fd);
            return Err(McpError::internal_error("dup stdout failed", None));
        }

        libc::dup2(write_fd, libc::STDOUT_FILENO);
        libc::close(write_fd);

        let reader_handle = std::thread::spawn(move || {
            let mut reader = std::fs::File::from_raw_fd(read_fd);
            let mut output = String::new();
            reader.read_to_string(&mut output).ok();
            output
        });

        let (code, buf) = f();
        std::io::stdout().flush().ok();

        libc::dup2(saved, libc::STDOUT_FILENO);
        libc::close(saved);

        let pipe_output = reader_handle.join().unwrap_or_default();

        // Combine: buf first (handler's intended output), then any residual stdout
        let mut combined = buf;
        if !pipe_output.is_empty() {
            combined.push_str(&pipe_output);
        }

        if code == 0 {
            Ok(CallToolResult::success(vec![Content::text(combined)]))
        } else {
            Ok(CallToolResult::error(vec![Content::text(combined)]))
        }
    }
}

/// Async variant of jjrm_capture_buf for handlers returning (i32, String).
async fn jjrm_capture_buf_async<F, Fut>(f: F) -> Result<CallToolResult, McpError>
where
    F: FnOnce() -> Fut,
    Fut: std::future::Future<Output = (i32, String)>,
{
    use std::io::{Read, Write};
    use std::os::unix::io::FromRawFd;

    unsafe {
        let mut fds = [0i32; 2];
        if libc::pipe(fds.as_mut_ptr()) != 0 {
            return Err(McpError::internal_error("pipe creation failed", None));
        }
        let (read_fd, write_fd) = (fds[0], fds[1]);

        let saved = libc::dup(libc::STDOUT_FILENO);
        if saved < 0 {
            libc::close(read_fd);
            libc::close(write_fd);
            return Err(McpError::internal_error("dup stdout failed", None));
        }
        libc::dup2(write_fd, libc::STDOUT_FILENO);
        libc::close(write_fd);

        let reader_handle = std::thread::spawn(move || {
            let mut reader = std::fs::File::from_raw_fd(read_fd);
            let mut output = String::new();
            reader.read_to_string(&mut output).ok();
            output
        });

        let (code, buf) = f().await;
        std::io::stdout().flush().ok();

        libc::dup2(saved, libc::STDOUT_FILENO);
        libc::close(saved);

        let pipe_output = reader_handle.join().unwrap_or_default();

        let mut combined = buf;
        if !pipe_output.is_empty() {
            combined.push_str(&pipe_output);
        }

        if code == 0 {
            Ok(CallToolResult::success(vec![Content::text(combined)]))
        } else {
            Ok(CallToolResult::error(vec![Content::text(combined)]))
        }
    }
}

